// Select motivational theme by day of week
const themes = [
  { theme: 'overcoming failure and resilience', audience: 'entrepreneurs and go-getters' },
  { theme: 'morning mindset for success', audience: 'professionals and students' },
  { theme: 'gratitude and abundance mindset', audience: 'families and individuals' },
  { theme: 'discipline beats motivation every time', audience: 'athletes and high-performers' },
  { theme: 'small steps lead to big dreams', audience: 'beginners and dreamers' },
  { theme: 'weekend warrior: recharge and refocus', audience: 'busy parents and workers' },
  { theme: 'Sunday reset: plan your best week', audience: 'goal-setters and planners' }
];

const day = new Date().getDay(); // 0=Sun, 6=Sat
const selected = themes[day];

return [{ json: { ...selected, date: new Date().toISOString().split('T')[0], dayIndex: day } }];

// Parse Claude's response
const response = $input.item.json;
const rawText = response.content?.[0]?.text || '{}';

let parsed;
try {
  // Try direct JSON parse first
  parsed = JSON.parse(rawText);
} catch(e) {
  // Try extracting JSON from markdown code blocks
  const match = rawText.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
  if (match) {
    try { parsed = JSON.parse(match[1]); } catch(e2) { parsed = {}; }
  } else {
    // Last resort: extract what we can
    parsed = {
      title: 'Motivational Video ' + new Date().toLocaleDateString(),
      script: rawText.slice(0, 1000),
      description: 'Daily motivation for your best life.',
      tags: ['motivation', 'success', 'mindset', 'inspiration', 'selfimprovement']
    };
  }
}

const theme = $('Pick Motivational Theme').item.json;
return [{ json: { ...parsed, theme: theme.theme, date: theme.date } }];

// Build final video metadata for YouTube upload
const scriptData = $('Parse Script & Metadata').item.json;

const tagsArray = Array.isArray(scriptData.tags)
  ? scriptData.tags
  : ['motivation', 'success', 'mindset', 'inspiration', 'selfimprovement', 'growthmindset', 'positivity'];

const description = `${scriptData.description || ''}

"${scriptData.quote || 'Success is not final, failure is not fatal.'}"

📌 Subscribe for daily motivation: https://youtube.com/@JoyfulFamilyMoments
👍 Like if this video inspired you!
🔔 Hit the bell for daily uploads!

${tagsArray.map(t => '#' + t.replace(/\s/g, '')).join(' ')}`;

return [{
  json: {
    title: scriptData.title,
    description: description,
    tags: tagsArray,
    categoryId: '26',
    privacyStatus: 'public',
    thumbnail_text: scriptData.thumbnail_text || 'YOU CAN DO IT',
    audioReady: true,
    ffmpegNote: 'Combine motivational background video + audio.mp3 using FFmpeg'
  }
}];

